+#include "PyNvCodec.hpp"
+
+using namespace std;
+using namespace VPF;
+using namespace chrono;
+
+namespace py = pybind11;
+
+constexpr auto TASK_EXEC_SUCCESS = TaskExecStatus::TASK_EXEC_SUCCESS;
+constexpr auto TASK_EXEC_FAIL = TaskExecStatus::TASK_EXEC_FAIL;
+
+PySurfaceRemaper::PySurfaceRemaper(const float* x_map, const float* y_map,
+                                   uint32_t width, uint32_t height,
+                                   Pixel_Format format, CUcontext ctx,
+                                   CUstream str)
+    : outputFormat(format)
+{
+  upRemaper.reset(RemapSurface::Make(x_map, y_map, width, height, format, ctx, str));
+}
+
+PySurfaceRemaper::PySurfaceRemaper(long x_map_ptr, long y_map_ptr,
+                                   uint32_t width, uint32_t height,
+                                   Pixel_Format format, CUcontext ctx,
+                                   CUstream str)
+    : outputFormat(format)
+{
+  const float* x_map = reinterpret_cast<const float*>(x_map_ptr);
+  const float* y_map = reinterpret_cast<const float*>(y_map_ptr);
+  upRemaper.reset(RemapSurface::Make(x_map, y_map, width, height, format, ctx, str));
+}
+
+PySurfaceRemaper::PySurfaceRemaper(long x_map_ptr, long y_map_ptr,
+                                   uint32_t width, uint32_t height,
+                                   Pixel_Format format, uint32_t gpuID)
+    : outputFormat(format)
+{
+  const float* x_map = reinterpret_cast<const float*>(x_map_ptr);
+  const float* y_map = reinterpret_cast<const float*>(y_map_ptr);
+  upRemaper.reset(RemapSurface::Make(x_map, y_map, width, height, format,
+			             CudaResMgr::Instance().GetCtx(gpuID),
+				     CudaResMgr::Instance().GetStream(gpuID)));
+}
+
+Pixel_Format PySurfaceRemaper::GetFormat() { return outputFormat; }
+
+shared_ptr<Surface> PySurfaceRemaper::Execute(shared_ptr<Surface> surface)
+{
+  if (!surface) {
+    return shared_ptr<Surface>(Surface::Make(outputFormat));
+  }
+
+  upRemaper->SetInput(surface.get(), 0U);
+
+  if (TASK_EXEC_SUCCESS != upRemaper->Execute()) {
+    return shared_ptr<Surface>(Surface::Make(outputFormat));
+  }
+
+  auto pSurface = (Surface*)upRemaper->GetOutput(0U);
+  return shared_ptr<Surface>(pSurface ? pSurface->Clone()
+                                      : Surface::Make(outputFormat));
+}
+
+void Init_PySurfaceRemaper(py::module& m)
+{
+  py::class_<PySurfaceRemaper>(m, "PySurfaceRemaper")
+      .def(py::init<long, long, uint32_t, uint32_t, Pixel_Format, uint32_t>())
+      .def(py::init<long, long, uint32_t, uint32_t, Pixel_Format, size_t, size_t>())
+      .def("Format", &PySurfaceRemaper::GetFormat)
+      .def("Execute", &PySurfaceRemaper::Execute,
+           py::return_value_policy::take_ownership,
+           py::call_guard<py::gil_scoped_release>());
+}
