+
+void FFmpegDemuxer::GetCuVideoFormat(CUVIDEOFORMAT* format)
+{
+  if (!format) {
+    return;
+  }
+
+  memset(format, 0, sizeof(*format));
+
+  // Video codec
+  if (is_mp4H264)
+    format->codec = cudaVideoCodec_H264;
+  if (is_mp4HEVC)
+    format->codec = cudaVideoCodec_HEVC;
+  if (is_VP9)
+    format->codec = cudaVideoCodec_VP9;
+
+  // Frame rate
+  format->frame_rate.numerator = fmtc->streams[videoStream]->avg_frame_rate.num;
+  format->frame_rate.denominator =
+      fmtc->streams[videoStream]->avg_frame_rate.den;
+
+  // Frame or field
+  format->progressive_sequence =
+      (AV_FIELD_PROGRESSIVE == fmtc->streams[videoStream]->codec->field_order);
+
+  // Bit depth
+  format->bit_depth_luma_minus8 = 0;
+  format->bit_depth_chroma_minus8 = format->bit_depth_luma_minus8;
+
+  // Coded width and height
+  format->coded_width = fmtc->streams[videoStream]->codec->coded_width;
+  format->coded_height = fmtc->streams[videoStream]->codec->coded_height;
+
+  // Number of decoded surfaces
+  format->min_num_decode_surfaces = GetNumDecodeSurfaces(
+      format->codec, format->coded_width, format->coded_height);
+
+  // Display area
+  format->display_area.top = 0;
+  format->display_area.left = 0;
+  format->display_area.right = fmtc->streams[videoStream]->codecpar->width;
+  format->display_area.bottom = fmtc->streams[videoStream]->codecpar->height;
+
+  // Chroma format;
+  switch (eChromaFormat) {
+  case AV_PIX_FMT_YUV420P:
+    format->chroma_format = cudaVideoChromaFormat_420;
+    break;
+  case AV_PIX_FMT_YUV422P:
+    format->chroma_format = cudaVideoChromaFormat_422;
+    break;
+  case AV_PIX_FMT_YUV444P:
+    format->chroma_format = cudaVideoChromaFormat_444;
+    break;
+  default:
+    format->chroma_format = cudaVideoChromaFormat_420;
+    break;
+  }
+
+  // Bitrate
+  format->bitrate = 0U;
+
+  // Aspect ratio
+  format->display_aspect_ratio.x = fmtc->streams[videoStream]->display_aspect_ratio.num;
+  format->display_aspect_ratio.y = fmtc->streams[videoStream]->display_aspect_ratio.den;
+}
