+      .def("UploadSingleFrame",
+           py::overload_cast<py::array_t<uint8_t>&>(
+               &PyFrameUploader::UploadSingleFrame),
+           py::arg("frame").noconvert(true),
+           py::return_value_policy::take_ownership,
+           py::call_guard<py::gil_scoped_release>())
