+  CudaCtxPush lock(context);
+  if (CUDA_SUCCESS != cuMemcpyHtoDAsync(pBuffer->GpuMem(), (const void *)pSrcHost,
+                                        pBuffer->GetRawMemSize(), stream)) {
+    return TASK_EXEC_FAIL;
+  }
+
+  SetOutput(pBuffer, 0);
+  return TASK_EXEC_SUCCESS;
