+  bool SaveYUV420(AVFrame *pframe) {
+    // Detect frame size & allocate memory if necessary;
+    size_t size = frame->width * frame->height * 3 / 2;
+
+    if (!dec_frame) {
+      dec_frame = Buffer::Make(size);
+    } else if (size != dec_frame->GetRawMemSize()) {
