+      auto *src = frame->data[plane];
+
+      auto width = (0 == plane) ? frame->width : frame->width / 2;
+      auto height = (0 == plane) ? frame->height : frame->height / 2;
+
+      for (int i = 0; i < height; i++) {
+        memcpy(dst, src, width);
+        dst += width;
+        src += frame->linesize[plane];
+      }
+
+      plane++;
+      pos += width * height;
+    }
+
+    return true;
+  }
