+TaskExecStatus FfmpegDecodeFrame::Execute() {
+  ClearOutputs();
+
+  if (pImpl->DecodeSingleFrame()) {
+    SetOutput((Token *)pImpl->dec_frame, 0U);
+    return TaskExecStatus::TASK_EXEC_SUCCESS;
+  }
+
+  return TaskExecStatus::TASK_EXEC_FAIL;
+}
