+#include "NvEncoderCLIOptions.h"
+#include <iostream>
+#include <sstream>
+#include <vector>
+
+using namespace std;
+using namespace VPF;
+
+auto GetCapabilityValue = [&](GUID guidCodec, NV_ENC_CAPS capsToQuery,
+                              NV_ENCODE_API_FUNCTION_LIST api_func,
+                              void *encoder) {
+  NV_ENC_CAPS_PARAM capsParam = {NV_ENC_CAPS_PARAM_VER};
+  capsParam.capsToQuery = capsToQuery;
+  int v;
+  api_func.nvEncGetEncodeCaps(encoder, guidCodec, &capsParam, &v);
+  return v;
+};
+
+auto FindAttribute = [&](const map<string, string> &options,
+                         const string &option) {
+  auto it = options.find(option);
+  if (it != options.end()) {
+    return it->second;
+  }
+
+  return string("");
+};
+
+auto FindCodecGuid = [&](const string &codec_name) {
+  static const map<string, GUID> codec_guids = {
+      {"h264", NV_ENC_CODEC_H264_GUID}, {"hevc", NV_ENC_CODEC_HEVC_GUID}};
+
+  auto it = codec_guids.find(codec_name);
+  if (it != codec_guids.end()) {
+    return it->second;
+  }
+
+  throw invalid_argument("Invalid codec given.");
+};
+
+auto FindPresetGuid = [&](const string &preset_name) {
+  static const map<string, GUID> preset_guids = {
+      {"default", NV_ENC_PRESET_DEFAULT_GUID},
+      {"hp", NV_ENC_PRESET_HP_GUID},
+      {"hq", NV_ENC_PRESET_HQ_GUID},
+      {"bd", NV_ENC_PRESET_BD_GUID},
+      {"ll", NV_ENC_PRESET_LOW_LATENCY_DEFAULT_GUID},
+      {"ll_hp", NV_ENC_PRESET_LOW_LATENCY_HP_GUID},
+      {"ll_hq", NV_ENC_PRESET_LOW_LATENCY_HQ_GUID},
+      {"lossless", NV_ENC_PRESET_LOSSLESS_DEFAULT_GUID},
+      {"lossless_hp", NV_ENC_PRESET_LOSSLESS_HP_GUID}};
+
+  auto it = preset_guids.find(preset_name);
+  if (it != preset_guids.end()) {
+    return it->second;
+  } else {
+    cerr << "Preset " << preset_name << " not found. Using default." << endl;
+    return NV_ENC_PRESET_DEFAULT_GUID;
+  }
+};
+
+auto ParseResolution = [&](const string &res_string, uint32_t &width,
+                           uint32_t &height) {
+  string::size_type xPos = res_string.find('x');
+
+  if (xPos != string::npos) {
+    // Parse width;
+    stringstream ssWidth;
+    ssWidth << res_string.substr(0, xPos);
+    ssWidth >> width;
+
+    // Parse height;
+    stringstream ssHeight;
+    ssHeight << res_string.substr(xPos + 1);
+    ssHeight >> height;
+  } else {
+    throw invalid_argument("Invalid resolution.");
+  }
+};
+
+template <typename T> T FromString(const string &value) {}
+
+template <> uint32_t FromString(const string &value) {
+  stringstream ss;
+  ss << value;
+
+  uint32_t ret;
+  ss >> ret;
+  return ret;
+}
+
+template <> uint16_t FromString(const string &value) {
+  stringstream ss;
+  ss << value;
+
+  uint16_t ret;
+  ss >> ret;
+  return ret;
+}
+
+template <> int FromString(const string &value) {
+  stringstream ss;
+  ss << value;
+
+  int ret;
+  ss >> ret;
+  return ret;
+}
+
+string ToString(const GUID &guid) {
+  // Codecs;
+  if (NV_ENC_CODEC_H264_GUID == guid) {
+    return "H.264";
+  } else if (NV_ENC_CODEC_HEVC_GUID == guid) {
+    return "H.265";
+  }
+  // Presets;
+  else if (NV_ENC_PRESET_DEFAULT_GUID == guid) {
+    return "Default";
+  } else if (NV_ENC_PRESET_HP_GUID == guid) {
+    return "HP";
+  } else if (NV_ENC_PRESET_HQ_GUID == guid) {
+    return "HQ";
+  } else if (NV_ENC_PRESET_BD_GUID == guid) {
+    return "BD";
+  } else if (NV_ENC_PRESET_LOW_LATENCY_DEFAULT_GUID == guid) {
+    return "LL";
+  } else if (NV_ENC_PRESET_LOW_LATENCY_HQ_GUID == guid) {
+    return "LLHQ";
+  } else if (NV_ENC_PRESET_LOW_LATENCY_HP_GUID == guid) {
+    return "LLHP";
+  } else if (NV_ENC_PRESET_LOSSLESS_DEFAULT_GUID == guid) {
+    return "Default";
+  } else if (NV_ENC_PRESET_LOSSLESS_HP_GUID == guid) {
+    return "Lossless";
+  }
+  // Profiles;
+  else if (NV_ENC_CODEC_PROFILE_AUTOSELECT_GUID == guid) {
+    return "Auto";
+  } else if (NV_ENC_H264_PROFILE_BASELINE_GUID == guid) {
+    return "Baseline";
+  } else if (NV_ENC_H264_PROFILE_MAIN_GUID == guid) {
+    return "Main";
+  } else if (NV_ENC_H264_PROFILE_HIGH_GUID == guid) {
+    return "High";
+  } else if (NV_ENC_H264_PROFILE_HIGH_444_GUID == guid) {
+    return "High YUV444";
+  } else if (NV_ENC_H264_PROFILE_STEREO_GUID == guid) {
+    return "Stereo";
+  } else if (NV_ENC_H264_PROFILE_SVC_TEMPORAL_SCALABILTY == guid) {
+    return "SVC";
+  } else if (NV_ENC_H264_PROFILE_PROGRESSIVE_HIGH_GUID == guid) {
+    return "Progressive High";
+  } else if (NV_ENC_H264_PROFILE_CONSTRAINED_HIGH_GUID == guid) {
+    return "Constrained high";
+  } else if (NV_ENC_HEVC_PROFILE_MAIN_GUID == guid) {
+    return "HEVC Main";
+  } else if (NV_ENC_HEVC_PROFILE_MAIN10_GUID == guid) {
+    return "HEVC Main 10 bit";
+  } else if (NV_ENC_HEVC_PROFILE_FREXT_GUID == guid) {
+    return "HEVC YUV444";
+  }
+  // Default;
+  else {
+    return "";
+  }
