+  if (!idr_period.empty()) {
+    config.idrPeriod = FromString<uint32_t>(idr_period);
+  }
+
+  // Number of reference frames in L0 and L1 lists;
+  auto num_ref_l0 = FindAttribute(options, "numrefl0");
+  if (!num_ref_l0.empty()) {
+    ParseNumRefFrames(num_ref_l0, config.numRefL0);
