+
+  auto num_ref_l1 = FindAttribute(options, "numrefl1");
+  if (!num_ref_l1.empty()) {
+    ParseNumRefFrames(num_ref_l1, config.numRefL1);
+  }
+#endif
+
+  SetupVuiConfig(config.h264VUIParameters, is_reconfigure, print_settings);
+
+  if (print_settings) {
+    PrintNvEncH264Config(config);
+  }
